theorem:
[Dynamical Non-Commutative Bifurcation]\label{thm:main_bifurcation}
Let $P_0(x)$ be a central polynomial over $\mathbb{A} \in \{\mathbb{H}, \mathbb{O}\}$ such that its root variety $V_0 = Z(P_0)$ contains a non-real manifold of dimension $d_{\rm M} > 0$. Let $P_\epsilon(x)$ be a generically non-central analytic deformation. Let $V_\epsilon = Z(P_\epsilon)$. Let $d_{\rm A} = \dim(\mathbb{A})$.
\begin{enumerate}
    \item \textbf{Topological Collapse:} The Hausdorff dimension of the root variety changes discontinuously at $\epsilon=0$.
    \item \textbf{Algebraic Singularity:} The central fiber $V_0$ is characterized by a Jacobian rank deficiency: $\rank(J_{P_0}(x)) = d_{\rm A} - d_{\rm M}$.
    \item \textbf{Dynamical Retraction:} Let $\mathcal{V}_\epsilon(x) = \|P_\epsilon(x)\|^2$. The gradient flow $\dot{x} = -\nabla\mathcal{V}_\epsilon(x)$ realizes the collapse as a deformation retract. The timescale exhibits critical slowing down: $T_{\rm collapse} \propto \epsilon^{-2}$.
    \item \textbf{Thermodynamic Phase Transition:} In a statistical ensemble at temperature $T$, the collapse manifests as a phase transition. An alignment order parameter $m(\epsilon,T)$ exhibits a discontinuity at $(\epsilon, T) = (0, 0)$.
\end{enumerate}

sketch:
To prove the main theorem, the proof "synthesizes the results established in the subsequent sections" and proceeds by parts:

\textbf{Part 1 (Topological Collapse):} For $\epsilon=0$, by the following result.

\begin{corollary}[Dimensional Inflation Law]\label{cor:inflation_law}
Let $\A$ be a real normed division algebra ($\C, \HH, \OO$) of dimension $d_{\rm A} \ge 2$. The dimension of the root manifold $M_{x_0}$ is $d_{\rm M} = d_{\rm A} - 2$.
\end{corollary}

For $\epsilon\neq 0$, "$G_{P_\epsilon}$ is trivial" and by the following theorem, the roots are isolated ($d_{\rm M}=0$).

\begin{theorem}[Generalized Symmetry Reduction Theorem]\label{thm:generalized_symmetry_reduction}
The root set $Z(P)$ is invariant under the action of $G_P$. The geometry of the root manifolds is determined by the orbits of $G_P$.
\end{theorem}

Hence the discontinuity follows from the following proposition.

\begin{proposition}[Topological Collapse]\label{prop:collapse}
For a generically non-central perturbation $P_\epsilon(x)$, the root manifold undergoes a topological phase transition. The Hausdorff dimension of the solution set $Z(P_\epsilon)$ changes discontinuously at $\epsilon=0$. (Part 1 of Main Theorem~\ref{thm:main_bifurcation}).
\end{proposition}

\textbf{Part 2 (Algebraic Singularity):} "The tangent space $T_x V_0$ is related to $\Ker(J_{P_0}(x))$." Therefore "the rank deficiency follows from the positive dimension of the manifold" by the following theorem.

\begin{theorem}[Jacobian Singularity of the Central Fiber]\label{thm:jacobian_singularity}
Let $V_0$ be the root manifold of a central polynomial $P_0$. The Jacobian $J_{P_0}(x)$ (viewed as a map $\R^{d_{\rm A}} \to \R^{d_{\rm A}}$) is singular for all $x \in V_0$. (Part 2 of Main Theorem~\ref{thm:main_bifurcation}).
\end{theorem}

\textbf{Part 3 (Dynamical Retraction):} "The potential $\mathcal{V}_\epsilon(x)$ is real-analytic and coercive." Then "the Lojasiewicz gradient inequality ... guarantees convergence of the gradient flow" via the following theorem.

\begin{theorem}[Deformation Retract]\label{thm:deformation_retract}
The gradient flow defines a deformation retract from the initial manifold $V_0$ onto the final set of attractors $V_\epsilon$. (Part 3 of Main Theorem~\ref{thm:main_bifurcation}).
\end{theorem}

The scaling "$T_{\rm collapse} \propto \epsilon^{-2}$ is derived from the quadratic scaling of the restricted potential" using the following theorem and proposition.

\begin{theorem}[Critical Slowing Down (Quadratic Scaling)]\label{thm:collapse_timescale}
The characteristic relaxation time $T_{\rm collapse}$ for the topological collapse under a generic non-central perturbation of magnitude $\epsilon$ scales as $T_{\rm collapse} \propto 1/\epsilon^2$.
\end{theorem}

\begin{proposition}[Lojasiewicz Exponent]\label{prop:lojasiewicz_exponent}
For a generic analytic perturbation (Morse function $f_\epsilon$), the Lojasiewicz exponent characterizing the flatness of the potential near the critical manifold $V_0$ is $\theta = 1/2$. This yields the quadratic timescale $T_{\rm collapse} \propto \epsilon^{-2}$. At non-generic perturbations (where the restricted potential is flatter than quadratic), $\theta$ may be smaller ($0 < \theta < 1/2$), leading to slower collapse timescales $T_{\rm collapse} \propto \epsilon^{-(1+\theta)/\theta}$.
\end{proposition}

\textbf{Part 4 (Thermodynamic Phase Transition):} "We define the Gibbs measure" as follows.

\begin{definition}[Gibbs Measure and Partition Function]\label{def:gibbs_measure}
The Gibbs probability measure $\mu_T$ on $\A$ is defined by
\begin{equation}
d\mu_T(x) = \frac{1}{Z(T)} \exp\left(-\frac{\mathcal{V}(x)}{T}\right) dx,
\end{equation}
where $Z(T) = \int_{\A} \exp(-\mathcal{V}(x)/T) dx$ is the partition function.
\end{definition}

and "the alignment order parameter $m(\epsilon, T)$" as follows.

\begin{definition}[Alignment Order Parameter]\label{def:order_parameter}
Let $\nu$ be a unit imaginary vector defining the perturbation axis. The alignment order parameter $m_\nu$ is the normalized mean square alignment of the coordinate along $\nu$ under the Gibbs measure. For $\HH$ ($d_{\rm A}=4$) aligned along $i$ (coordinate $b$):
\begin{equation}
m(\epsilon, T) = \frac{\langle b^2 \rangle_{\mu_T(\epsilon)}}{\langle b^2+c^2+d^2 \rangle_{\mu_T(\epsilon)}}.
\end{equation}
\end{definition}

As "$T\to 0$, the measure concentrates on $V_\epsilon$." For $\epsilon=0$, "symmetry implies $m(0, 0) = 1/(d_{\rm A}-1)$." For $\epsilon\neq 0$, the following theorem implies alignment, $m(\epsilon, 0) = 1$.

\begin{theorem}[Localization Theorem (Gordon-Motzkin)]\label{thm:algebraic_alignment}
Let $\A$ be a real normed division algebra ($\C, \HH, \OO$). Let $P(x) \in \A[x]$. Any isolated root $x_0$ of $P(x)$ belongs to the coefficient subalgebra $\A(P)$.
\end{theorem}

The discontinuity characterizes the phase transition by the following theorem.

\begin{theorem}[Symmetry Breaking and Phase Transition]\label{thm:phase_transition}
Consider a perturbation $P_\epsilon(x)$ breaking the symmetry along the $\nu$-axis. We analyze the behavior in the zero temperature limit ($T \to 0$). (Part 4 of Main Theorem~\ref{thm:main_bifurcation}).
\begin{enumerate}
    \item \textbf{Symmetric Phase (Disordered):} For $\epsilon=0$, the measure concentrates uniformly on $S^{d_{\rm A}-2}$. $m(0, 0) = 1/(d_{\rm A}-1)$.
    \item \textbf{Ordered Phase (Aligned):} For $\epsilon \neq 0$, the measure concentrates on the isolated roots aligned with the $\nu$-axis. $m(\epsilon, 0) = 1$.
\end{enumerate}
\end{theorem}

