q>0,\quad 0<\theta<1,\\
&\label{(3)}
f\geq0,\;\; f\not\equiv0,\quad f\in L^{1}(\Omega),\\
&\label{(4)}
2\leq p_{1}\leq p_{2}\leq ... \leq p_{N-1}\leq p_{N}\quad \mbox{and}\quad 2\leq \overline{p}:=N\left(\sum\limits_{j\in J}\frac{1}{p_{j}}\right)^{-1}<N.
