hold. Then,
\begin{itemize}
\item[(i)] If $0<q<1-\theta$, there exists a distributional solution $u\in W_{0}^{1,(r_{j})}(\Omega)$ to problem
\begin{equation}
\label{(1)}
\left\{\begin{array}{ll}\displaystyle-\sum\limits_{j\in J} D_{j}\left(\left[a(x)+u^{q}\right]\vert D_{j}u\vert^{p_{j}-2} D_{j}u\right)+b(x)\sum\limits_{j\in J}\frac{\vert D_{j}u\vert^{p_{j}}}{ u^{\theta}}=f& \hbox{in}\;\Omega, \\
u>0& \hbox{in}\;\Omega, \\
 u  =0 & \hbox{on}\; \partial\Omega, \end{array}
 \right.
\end{equation}
such that
\begin{align}
\label{(17)}
r_{j}=\frac{N(\overline{p}-\theta)}{\overline{p}(N-\theta)}p_{j},\quad \forall \; j\in J.
\end{align}
\item[(ii)] If $1-\theta<q\leq1$, there exists a distributional solution $u\in W_{0}^{1,(\eta_{j})}(\Omega)$ to the above problem such that
