\tThere exist constants $c=c(\data)$ and $\theta_0=\theta_0(n,p)\in(0,1)$ such that for any $\theta\in(\theta_0,1)$ there holds
\t\begin{align*}
int_{Q_{\rho}^\la(z_0)}H(z,|\na u|)\,dz
int_{Q_{2\rho}^\la(z_0)}H(z,|F|)\,dz\,.
\t\end{align*}\t
\end{lemma}
\begin{lemma}\label{q_reverse_lem}
Suppose \ref{q1} and \ref{q2}.
